/* ===== IFD Badminton Match Scheduler — sporty, sleek UI ===== */
:root {
  --court: #0b6b3a;          /* badminton court green */
  --court-dark: #083d23;
  --court-deep: #06301b;
  --line: #e9f5ee;
  --accent: #d7ff3e;         /* shuttle / energy lime */
  --accent-2: #00e0b8;       /* teal pop */
  --ink: #0e1a14;
  --paper: #ffffff;
  --muted: #6a7b72;
  --bg: #eef3f0;
  --shadow: 0 10px 30px rgba(8, 40, 25, .12);
  --radius: 16px;
  --wa: #25d366;
}

* { box-sizing: border-box; }
html, body { margin: 0; padding: 0; }
body {
  font-family: "Segoe UI", system-ui, -apple-system, Roboto, Helvetica, Arial, sans-serif;
  color: var(--ink);
  background:
    radial-gradient(1200px 500px at 80% -10%, rgba(0, 224, 184, .12), transparent),
    var(--bg);
  line-height: 1.45;
  -webkit-font-smoothing: antialiased;
}

/* ---------- Banner ---------- */
.banner {
  background: linear-gradient(135deg, var(--court-deep), var(--court) 55%, #0a8a4a);
  color: #fff;
  position: relative;
  overflow: hidden;
  box-shadow: var(--shadow);
}
.banner-inner {
  max-width: 1080px; margin: 0 auto; padding: 26px 20px;
  display: flex; align-items: center; justify-content: space-between; gap: 20px;
  position: relative; z-index: 2;
}
.logo { display: flex; align-items: center; gap: 16px; }
.shuttle {
  font-size: 46px; line-height: 1;
  filter: drop-shadow(0 4px 8px rgba(0,0,0,.35));
  animation: float 3.2s ease-in-out infinite;
}
@keyframes float { 0%,100%{ transform: translateY(0) rotate(-6deg);} 50%{ transform: translateY(-7px) rotate(6deg);} }
.logo-text h1 {
  margin: 0; font-size: clamp(1.25rem, 3.6vw, 2.1rem); letter-spacing: .3px; font-weight: 800;
}
.tagline { margin: 2px 0 0; color: var(--accent); font-weight: 600; font-size: .92rem; letter-spacing: .4px; }
.banner-court {
  position: absolute; inset: 0; z-index: 1; opacity: .16;
  background-image:
    linear-gradient(#fff 0 0), linear-gradient(#fff 0 0),
    linear-gradient(#fff 0 0), linear-gradient(#fff 0 0),
    linear-gradient(#fff 0 0);
  background-repeat: no-repeat;
  background-size: 100% 3px, 100% 3px, 3px 100%, 3px 100%, 100% 3px;
  background-position: 0 18%, 0 82%, 22% 0, 78% 0, 0 50%;
}

/* ---------- Layout ---------- */
.wrap { max-width: 1080px; margin: 0 auto; padding: 22px 16px 40px; }
.card {
  background: var(--paper); border-radius: var(--radius); padding: 22px;
  box-shadow: var(--shadow); margin-bottom: 22px; border: 1px solid #e4ece8;
}
.section-title { margin: 0 0 16px; font-size: 1.18rem; display: flex; align-items: center; gap: 9px; }
.section-title small { font-weight: 500; color: var(--muted); font-size: .8rem; }
.ico { font-size: 1.1em; }

/* ---------- Fields ---------- */
.grid { display: grid; gap: 14px; }
.params { grid-template-columns: repeat(4, 1fr); }
.tune { grid-template-columns: repeat(4, 1fr); }
.field { display: flex; flex-direction: column; gap: 6px; font-size: .86rem; font-weight: 600; color: #29382f; }
.field small { color: var(--muted); font-weight: 500; }
input, select {
  font: inherit; padding: 10px 12px; border: 1.6px solid #d6e2db; border-radius: 10px;
  background: #fbfdfc; color: var(--ink); transition: border-color .15s, box-shadow .15s;
}
input:focus, select:focus { outline: none; border-color: var(--court); box-shadow: 0 0 0 3px rgba(11,107,58,.15); }

/* ---------- Players ---------- */
.players-head { display: flex; align-items: center; justify-content: space-between; margin: 22px 0 8px; }
.players-head h3 { margin: 0; font-size: 1.02rem; }
.players-actions { display: flex; gap: 8px; }
.players-legend, .player-row {
  display: grid; grid-template-columns: 30px 1fr 110px 90px; gap: 10px; align-items: center;
}
.players-legend { padding: 4px 4px 6px; font-size: .74rem; text-transform: uppercase; letter-spacing: .5px; color: var(--muted); font-weight: 700; }
.players-legend .cen, .player-row .cen { text-align: center; }
.player-list { display: flex; flex-direction: column; gap: 8px; max-height: 360px; overflow-y: auto; padding: 2px; }
.player-row { background: #f6faf8; border: 1px solid #e6efea; border-radius: 10px; padding: 7px 9px; }
.player-row .idx { color: var(--muted); font-weight: 700; text-align: center; font-size: .85rem; }
.player-row input[type=text] { padding: 8px 10px; }
.player-row select { padding: 8px 8px; }
.gender-toggle { display: flex; align-items: center; justify-content: center; }
.gender-toggle input { width: 18px; height: 18px; accent-color: #d6336c; }

.balance-bar {
  margin: 16px 0 18px; font-size: .85rem; font-weight: 600; color: #29382f;
  background: #f1f7f4; border: 1px dashed #c9ddd2; border-radius: 10px; padding: 10px 12px;
  display: flex; flex-wrap: wrap; gap: 8px 18px; align-items: center;
}
.balance-bar .pill { background: #fff; border: 1px solid #dceae3; border-radius: 999px; padding: 3px 10px; font-weight: 700; }
.balance-bar .pill.warn { border-color: #f0b429; background: #fff8e6; }

/* ---------- Buttons ---------- */
.btn {
  font: inherit; font-weight: 700; border: none; border-radius: 11px; padding: 11px 16px;
  cursor: pointer; display: inline-flex; align-items: center; gap: 8px; transition: transform .08s, box-shadow .15s, background .15s;
}
.btn:active { transform: translateY(1px); }
.btn.primary { background: linear-gradient(135deg, var(--court), #0a8a4a); color: #fff; box-shadow: 0 6px 16px rgba(11,107,58,.3); }
.btn.primary:hover { box-shadow: 0 8px 22px rgba(11,107,58,.42); }
.btn.big { width: 100%; justify-content: center; font-size: 1.05rem; padding: 14px; margin-top: 6px; }
.btn.ghost { background: #eef4f1; color: #1f3329; }
.btn.ghost:hover { background: #e1ece7; }
.btn.whatsapp { background: var(--wa); color: #fff; box-shadow: 0 6px 16px rgba(37,211,102,.32); }
.btn.whatsapp:hover { filter: brightness(1.05); }

.err { color: #d6336c; font-weight: 600; margin: 12px 0 0; min-height: 1em; }

/* ---------- Custom rules ---------- */
.custom-rules { margin-top: 18px; border-top: 1px solid #eef3f0; padding-top: 16px; }
.custom-rules h3 { margin: 0 0 10px; font-size: .98rem; }
.add-rule { display: flex; gap: 8px; }
.add-rule input { flex: 1; }
.custom-rule-list { list-style: none; padding: 0; margin: 12px 0 6px; display: flex; flex-direction: column; gap: 6px; }
.custom-rule-list li {
  background: #f6faf8; border: 1px solid #e6efea; border-radius: 9px; padding: 8px 12px;
  display: flex; align-items: center; justify-content: space-between; gap: 10px; font-size: .9rem;
}
.custom-rule-list button { background: none; border: none; color: #d6336c; cursor: pointer; font-weight: 800; font-size: 1rem; }
.hint { color: var(--muted); font-size: .8rem; margin: 6px 0 0; }

/* ---------- Output toolbar ---------- */
.output-toolbar { display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 12px; margin: 6px 0 14px; }
.toolbar-btns { display: flex; gap: 10px; flex-wrap: wrap; }

/* ---------- Printable schedule ---------- */
.printable { background: var(--paper); border-radius: var(--radius); padding: 22px; box-shadow: var(--shadow); border: 1px solid #e4ece8; }
.print-head { text-align: center; border-bottom: 3px solid var(--court); padding-bottom: 12px; margin-bottom: 16px; }
.print-head h2 { margin: 0; color: var(--court-dark); font-size: 1.4rem; }
.print-meta { margin: 6px 0 0; color: var(--muted); font-size: .88rem; font-weight: 600; }

.round-block { margin-bottom: 18px; break-inside: avoid; }
.round-title {
  display: flex; align-items: center; gap: 10px; margin: 0 0 8px;
  font-size: 1.02rem; font-weight: 800; color: var(--court-dark);
}
.round-title .tag {
  font-size: .68rem; text-transform: uppercase; letter-spacing: .6px; padding: 2px 9px; border-radius: 999px;
  background: #eafdf4; color: #07623a; border: 1px solid #bde8d3; font-weight: 800;
}
.round-title .tag.mixed { background: #eef4ff; color: #1d4ed8; border-color: #c7d7ff; }
.round-title .tag.mens { background: #eefaf3; color: #07623a; border-color: #bde8d3; }
.round-title .tag.womens { background: #fdeef6; color: #b21e6b; border-color: #f3c6df; }

table.sched { width: 100%; border-collapse: collapse; font-size: .92rem; }
table.sched th, table.sched td { border: 1px solid #dbe7e1; padding: 9px 10px; text-align: left; }
table.sched th { background: var(--court); color: #fff; font-weight: 700; font-size: .8rem; text-transform: uppercase; letter-spacing: .4px; }
table.sched tr:nth-child(even) td { background: #f7fbf9; }
table.sched .court-col { width: 64px; text-align: center; font-weight: 800; color: var(--court-dark); }
table.sched .vs { width: 44px; text-align: center; color: var(--muted); font-weight: 800; }
.team { font-weight: 600; }
.team .lvl { color: var(--muted); font-weight: 600; font-size: .82em; }
.team .w { color: #d6336c; }
.mtag { font-size: .7rem; font-weight: 800; padding: 1px 7px; border-radius: 999px; background: #eef4ff; color: #1d4ed8; }
.mtag.mens { background: #eefaf3; color: #07623a; }
.mtag.womens { background: #fdeef6; color: #b21e6b; }

.rest-summary { margin-top: 8px; font-size: .9rem; }
.rest-summary .rest-line { padding: 6px 0; border-top: 1px dashed #d8e6df; }
.rest-summary b { color: var(--court-dark); }
.print-notes { margin-top: 14px; font-size: .85rem; color: #33433b; }
.print-notes ul { margin: 6px 0 0; padding-left: 18px; }

/* ---------- Rules section ---------- */
.rules-intro { color: #33433b; font-size: .92rem; margin: 0 0 14px; }
.rule-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px 18px; margin: 0; padding-left: 18px; }
.rule-grid li { font-size: .88rem; padding: 2px 0; }
.rule-grid b { color: var(--court-dark); }

.foot { text-align: center; color: var(--muted); font-size: .82rem; padding: 10px 16px 30px; }

/* ---------- Toast ---------- */
.toast {
  position: fixed; left: 50%; bottom: 28px; transform: translateX(-50%) translateY(20px);
  background: #0e1a14; color: #fff; padding: 11px 18px; border-radius: 999px; font-weight: 600; font-size: .9rem;
  opacity: 0; pointer-events: none; transition: opacity .2s, transform .2s; z-index: 50; box-shadow: var(--shadow);
}
.toast.show { opacity: 1; transform: translateX(-50%) translateY(0); }

/* ---------- Responsive ---------- */
@media (max-width: 720px) {
  .params, .tune { grid-template-columns: 1fr 1fr; }
  .rule-grid { grid-template-columns: 1fr; }
  .players-legend, .player-row { grid-template-columns: 24px 1fr 92px 64px; gap: 7px; }
}
@media (max-width: 430px) {
  .params, .tune { grid-template-columns: 1fr; }
}

/* ---------- Print: only the schedule table ---------- */
@media print {
  body { background: #fff; }
  .no-print, .banner, .foot { display: none !important; }
  .wrap { max-width: none; margin: 0; padding: 0; }
  #output { display: block !important; }
  .printable { box-shadow: none; border: none; border-radius: 0; padding: 0; }
  .print-head h2 { color: #000; }
  table.sched th { background: #0b6b3a !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  .round-block { break-inside: avoid; }
}

