  background: #0e1a14; color: #fff; padding: 11px 18px; border-radius: 999px; font-weight: 600; font-size: .9rem;
  opacity: 0; pointer-events: none; transition: opacity .2s, transform .2s; z-index: 50; box-shadow: var(--shadow);
}
.toast.show { opacity: 1; transform: translateX(-50%) translateY(0); }

/* ---------- Responsive ---------- */
@media (max-width: 720px) {
  .params, .tune { grid-template-columns: 1fr 1fr; }
  .rule-grid { grid-template-columns: 1fr; }
  .players-legend, .player-row { grid-template-columns: 24px 1fr 92px 64px; gap: 7px; }
}
@media (max-width: 430px) {
  .params, .tune { grid-template-columns: 1fr; }
}

/* ---------- Print: only the schedule table ---------- */
@media print {
  body { background: #fff; }
  .no-print, .banner, .foot { display: none !important; }
  .wrap { max-width: none; margin: 0; padding: 0; }
  #output { display: block !important; }
  .printable { box-shadow: none; border: none; border-radius: 0; padding: 0; }
  .print-head h2 { color: #000; }
  table.sched th { background: #0b6b3a !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  .round-block { break-inside: avoid; }
}

