/* =========================================================================
   IFD Badminton Match Scheduler
   Pure client-side. No login, no storage. Everything lives in memory and
   disappears on refresh.
   ========================================================================= */

(() => {
  "use strict";

  const $ = (id) => document.getElementById(id);
  const LEVELS = ["L1", "L2", "L3", "L4"];

  // -------- session state (memory only) --------
  const state = {
    customRules: [],      // free-text notes added during the session
    lastSchedule: null,   // last generated schedule (for share/print)
  };

  /* ---------------------------------------------------------------------
     PLAYER INPUT ROWS
     --------------------------------------------------------------------- */
  const SAMPLE = ["Arjun","Riya","Sam","Neha","Vikram","Priya","Karan","Anita",
    "Rahul","Meera","Dev","Sara","Aman","Tara","Rohit","Isha","Nikhil","Pooja",
    "Varun","Divya","Kabir","Lina","Yash","Gauri"];

  function buildPlayerRows() {
    const n = clampInt($("numPlayers").value, 4, 60, 12);
    const list = $("playerList");
    const existing = readPlayers(); // keep what's already typed
    list.innerHTML = "";
    for (let i = 0; i < n; i++) {
      const prev = existing[i] || {};
      const row = document.createElement("div");
      row.className = "player-row";
      row.innerHTML = `
        <span class="idx">${i + 1}</span>
        <input type="text" class="p-name" placeholder="Player ${i + 1}" value="${esc(prev.name || "")}" />
        <select class="p-level">
          ${LEVELS.map(l => `<option value="${l}" ${prev.level === l ? "selected" : ""}>${l}</option>`).join("")}
        </select>
        <span class="gender-toggle">
          <input type="checkbox" class="p-woman" ${prev.woman ? "checked" : ""} title="Tick if the player is a woman" />
        </span>`;
      list.appendChild(row);
    }
    updateBalanceBar();
  }

  function readPlayers() {
    const rows = [...document.querySelectorAll(".player-row")];
    return rows.map((r, i) => ({
      id: i,
      name: r.querySelector(".p-name").value.trim(),
      level: r.querySelector(".p-level").value,
      woman: r.querySelector(".p-woman").checked,
    }));
  }

  function updateBalanceBar() {
    const players = readPlayers();
    const named = players.filter(p => p.name);
    const women = named.filter(p => p.woman).length;
    const men = named.length - women;
    const pct = named.length ? Math.round((women / named.length) * 100) : 0;
    const byLvl = LEVELS.map(l => `${l}:${named.filter(p => p.level === l).length}`).join("  ");
    const womenWarn = pct > 40 ? "warn" : "";
    $("balanceBar").innerHTML = `
      <span class="pill">👥 ${named.length} named</span>
      <span class="pill">♂ ${men}</span>
      <span class="pill ${womenWarn}">♀ ${women} (${pct}%)</span>
      <span class="pill">${byLvl}</span>
      ${pct > 40 ? '<span class="pill warn">women &gt; 40% → women\'s doubles enabled</span>' : ""}`;
  }

  /* ---------------------------------------------------------------------
     HELPERS
     --------------------------------------------------------------------- */
  const clampInt = (v, min, max, def) => {
    let n = parseInt(v, 10);
    if (isNaN(n)) n = def;
    return Math.max(min, Math.min(max, n));
  };
  const esc = (s) => String(s).replace(/[&<>"']/g, c => (
    { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));
  const lvlNum = (l) => LEVELS.indexOf(l) + 1; // L1->1 ... L4->4
  const shuffle = (arr) => {
    const a = arr.slice();
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  };
  const pairKey = (a, b) => [a.id, b.id].sort((x, y) => x - y).join("-");

  // strength of a player on a "skill" scale where higher = stronger,
  // honouring the user's L1/L4 direction choice.
  function skill(p) {
    const dir = $("strongDir").value;
    return dir === "low" ? (5 - lvlNum(p.level)) : lvlNum(p.level);
  }

  /* ---------------------------------------------------------------------
     SCHEDULE PLANNING — decide a target type per round
     --------------------------------------------------------------------- */
  function planRoundTypes(players, rounds) {
    const women = players.filter(p => p.woman);
    const men = players.filter(p => !p.woman);
    const womenPct = players.length ? women.length / players.length : 0;

    let mens = clampInt($("mensRounds").value, 0, rounds, 1);
    let womens = clampInt($("womensRounds").value, 0, rounds, 0);

    // Need at least 4 of a gender to even attempt that doubles type.
    if (men.length < 4) mens = 0;
    if (women.length < 4) womens = 0;
    // Rule E: only push women's doubles automatically when > 40% women.
    if (womenPct <= 0.40 && $("womensRounds").value === "") womens = 0;

    mens = Math.min(mens, Math.max(0, rounds - womens));

    const types = new Array(rounds).fill("mixed");
    // Spread special rounds across the schedule rather than clumping them.
    const special = [];
    for (let i = 0; i < mens; i++) special.push("mens");
    for (let i = 0; i < womens; i++) special.push("womens");
    if (special.length) {
      const step = rounds / (special.length + 1);
      special.forEach((t, i) => {
        let pos = Math.round(step * (i + 1)) - 1;
        pos = Math.max(0, Math.min(rounds - 1, pos));
        while (types[pos] !== "mixed" && pos < rounds - 1) pos++;
        while (types[pos] !== "mixed" && pos > 0) pos--;
        types[pos] = t;
      });
    }
    return types;
  }

  /* ---------------------------------------------------------------------
     REST SELECTION (rule F) — fair rotation, no back-to-back rest
     --------------------------------------------------------------------- */
  function chooseResters(players, restNeeded, restCount, lastRest) {
    if (restNeeded <= 0) return [];
    // Prefer players who have rested the least and did NOT rest last round.
    const pool = shuffle(players);
    pool.sort((a, b) => {
      const aLast = lastRest.has(a.id) ? 1 : 0;
      const bLast = lastRest.has(b.id) ? 1 : 0;
      if (aLast !== bLast) return aLast - bLast;          // last-round resters go last
      return (restCount[a.id] || 0) - (restCount[b.id] || 0); // fewest rests first
    });
    return pool.slice(0, restNeeded);
  }

  /* ---------------------------------------------------------------------
     TEAM FORMATION for one round
     --------------------------------------------------------------------- */
  function makeTeams(active, type, ctx, relax) {
    const remaining = shuffle(active);
    const teams = [];
    const wantOpposite = type === "mixed";

    while (remaining.length) {
      const a = remaining.shift();
      let best = -1, bestScore = Infinity;

      for (let j = 0; j < remaining.length; j++) {
        const b = remaining[j];

        // Hard: no repeat partnership unless relaxed (rule H / I)
        if (relax < 1 && ctx.partnerUsed.has(pairKey(a, b))) continue;

        // Gender fit per round type
        const opposite = a.woman !== b.woman;
        if (relax < 1) {
          if (type === "mens" && (a.woman || b.woman)) continue;
          if (type === "womens" && (!a.woman || !b.woman)) continue;
        }

        let s = 0;
        if (wantOpposite && !opposite) s += 6;             // prefer M+F for mixed
        if (!wantOpposite && opposite && relax < 1) s += 8; // keep same-gender for mens/womens
        s += Math.abs(skill(a) - skill(b)) * 0.5;          // mild: avoid wildly mismatched partners
        if (ctx.lastPartner[a.id] === b.id) s += 5;        // rule B: not same partner as last round
        s += Math.random() * 1.5;                          // keep it fresh

        if (s < bestScore) { bestScore = s; best = j; }
      }

      if (best === -1) {
        if (remaining.length === 0) return null;           // dangling player
        best = 0;                                          // forced pick (relaxed)
      }
      const partner = remaining.splice(best, 1)[0];
      teams.push([a, partner]);
    }
    return teams;
  }

  /* ---------------------------------------------------------------------
     MATCH FORMATION — pair teams into courts (rules C, G, H)
     --------------------------------------------------------------------- */
  function makeMatches(teams, ctx, maxGap, relax) {
    const remaining = shuffle(teams);
    const matches = [];

    while (remaining.length >= 2) {
      const t1 = remaining.shift();
      let best = -1, bestScore = Infinity;

      for (let j = 0; j < remaining.length; j++) {
        const t2 = remaining[j];
        const four = [...t1, ...t2];
        const levels = four.map(p => lvlNum(p.level));
        const spread = Math.max(...levels) - Math.min(...levels);

        // Rule C: level spread within match (relax >=2 overrules — rule I)
        if (relax < 2 && spread > maxGap) continue;
        // Rule H: avoid repeating the exact same match-up
        const mk = matchKey(t1, t2);
        if (relax < 1 && ctx.matchupUsed.has(mk)) continue;

        // Rule G: opposing teams should be similarly balanced.
        const s1 = t1.reduce((x, p) => x + skill(p), 0);
        const s2 = t2.reduce((x, p) => x + skill(p), 0);
        let s = Math.abs(s1 - s2) * 2;          // close team strengths
        s += spread * 0.6;                       // tighter levels preferred
        // Reward "mirror" structure: both teams strong+weak vs both balanced
        const gap1 = Math.abs(skill(t1[0]) - skill(t1[1]));
        const gap2 = Math.abs(skill(t2[0]) - skill(t2[1]));
        s += Math.abs(gap1 - gap2) * 1.5;
        s += Math.random();

        if (s < bestScore) { bestScore = s; best = j; }
      }

      if (best === -1) {
        if (relax < 2) return null;
        best = 0;
      }
      const t2 = remaining.splice(best, 1)[0];
      matches.push([t1, t2]);
    }
    return matches;
  }

  const matchKey = (t1, t2) => {
    const k1 = t1.map(p => p.id).sort((a, b) => a - b).join("-");
    const k2 = t2.map(p => p.id).sort((a, b) => a - b).join("-");
    return [k1, k2].sort().join("|");
  };

  function matchType(match) {
    const all = [...match[0], ...match[1]];
    const women = all.filter(p => p.woman).length;
    if (women === 0) return "mens";
    if (women === all.length) return "womens";
    // mixed if each team is one of each
    const teamMixed = match.every(t => t[0].woman !== t[1].woman);
    return teamMixed ? "mixed" : "mixed";
  }

  /* ---------------------------------------------------------------------
     BUILD ONE ROUND (with relaxation ladder — rule I)
     --------------------------------------------------------------------- */
  function buildRound(active, courts, type, ctx, maxGap) {
    const matchCount = Math.min(courts, Math.floor(active.length / 4));
    const playing = matchCount * 4;
    // active already trimmed to `playing` by caller
    const ATTEMPTS = 600;

    for (let relax = 0; relax <= 2; relax++) {
      let best = null, bestScore = Infinity;
      for (let a = 0; a < ATTEMPTS; a++) {
        const teams = makeTeams(active, type, ctx, relax);
        if (!teams) continue;
        const matches = makeMatches(teams, ctx, maxGap, relax);
        if (!matches) continue;
        const score = scoreRound(matches, type, ctx);
        if (score < bestScore) { bestScore = score; best = matches; }
      }
      if (best) return { matches: best, relaxed: relax };
    }
    return null;
  }

  function scoreRound(matches, targetType, ctx) {
    let s = 0;
    for (const m of matches) {
      const all = [...m[0], ...m[1]];
      const levels = all.map(p => lvlNum(p.level));
      s += (Math.max(...levels) - Math.min(...levels)) * 1.2;
      const s1 = m[0].reduce((x, p) => x + skill(p), 0);
      const s2 = m[1].reduce((x, p) => x + skill(p), 0);
      s += Math.abs(s1 - s2) * 2;
      if (matchType(m) !== targetType) s += 4;          // honour planned round type
      for (const t of m) {
        if (ctx.partnerUsed.has(pairKey(t[0], t[1]))) s += 6;
        if (ctx.lastPartner[t[0].id] === t[1].id) s += 4;
      }
    }
    return s;
  }

  /* ---------------------------------------------------------------------
     FULL SCHEDULE
     --------------------------------------------------------------------- */
  function generateSchedule(players, courts, rounds, maxGap) {
    const ctx = {
      partnerUsed: new Set(),
      matchupUsed: new Set(),
      lastPartner: {},   // playerId -> partnerId in previous round
      restCount: {},
      lastRest: new Set(),
    };
    const types = planRoundTypes(players, rounds);
    const schedule = [];

    const slots = courts * 4;
    for (let r = 0; r < rounds; r++) {
      const restNeeded = Math.max(0, players.length - slots);
      const resters = chooseResters(players, restNeeded, ctx.restCount, ctx.lastRest);
      const restIds = new Set(resters.map(p => p.id));
      let active = players.filter(p => !restIds.has(p.id));
      // trim to a multiple of 4 (some courts may go unused if short)
      const playing = Math.min(courts, Math.floor(active.length / 4)) * 4;
      const benched = active.slice(playing);       // couldn't be placed this round
      active = active.slice(0, playing);

      const round = buildRound(active, courts, types[r], ctx, maxGap);
      const allResters = [...resters, ...benched];

      // update context
      ctx.lastRest = new Set(allResters.map(p => p.id));
      allResters.forEach(p => { ctx.restCount[p.id] = (ctx.restCount[p.id] || 0) + 1; });
      const newLastPartner = {};
      if (round) {
        for (const m of round.matches) {
          for (const t of m) {
            ctx.partnerUsed.add(pairKey(t[0], t[1]));
            newLastPartner[t[0].id] = t[1].id;
            newLastPartner[t[1].id] = t[0].id;
          }
          ctx.matchupUsed.add(matchKey(m[0], m[1]));
        }
      }
      ctx.lastPartner = newLastPartner;

      schedule.push({
        round: r + 1,
        plannedType: types[r],
        matches: round ? round.matches : [],
        relaxed: round ? round.relaxed : 0,
        rest: allResters,
      });
    }
    return schedule;
  }

  /* ---------------------------------------------------------------------
     RENDER
     --------------------------------------------------------------------- */
  function teamHtml(team) {
    return team.map(p =>
      `<span>${esc(p.name)}<span class="lvl"> ·${p.level}${p.woman ? '<span class="w"> ♀</span>' : ''}</span></span>`
    ).join(" &amp; ");
  }

  function renderSchedule(schedule, meta) {
    const host = $("scheduleTables");
    host.innerHTML = "";
    schedule.forEach(rnd => {
      const block = document.createElement("div");
      block.className = "round-block";
      const tagClass = rnd.plannedType;
      const rows = rnd.matches.map((m, i) => {
        const mt = matchType(m);
        return `<tr>
          <td class="court-col">${i + 1}</td>
          <td class="team">${teamHtml(m[0])}</td>
          <td class="vs">vs</td>
          <td class="team">${teamHtml(m[1])}</td>
          <td><span class="mtag ${mt}">${mt === "mens" ? "Men's" : mt === "womens" ? "Women's" : "Mixed"}</span></td>
        </tr>`;
      }).join("");
      const restTxt = rnd.rest.length
        ? `<div class="rest-line">🪑 <b>Resting:</b> ${rnd.rest.map(p => esc(p.name)).join(", ")}</div>` : "";
      const relaxNote = rnd.relaxed >= 2
        ? ' <span class="tag" title="Level gap relaxed to fill the schedule (rule I)">↯ levels relaxed</span>'
        : rnd.relaxed >= 1
        ? ' <span class="tag" title="Repeat pairing allowed to fill the schedule (rule I)">↯ repeat allowed</span>' : "";
      block.innerHTML = `
        <h3 class="round-title">Round ${rnd.round}
          <span class="tag ${tagClass}">${tagClass === "mens" ? "Men's focus" : tagClass === "womens" ? "Women's focus" : "Mixed"}</span>${relaxNote}
        </h3>
        <table class="sched">
          <thead><tr><th>Court</th><th>Team A</th><th></th><th>Team B</th><th>Type</th></tr></thead>
          <tbody>${rows || '<tr><td colspan="5">No match could be formed.</td></tr>'}</tbody>
        </table>
        ${restTxt}`;
      host.appendChild(block);
    });

    $("printMeta").textContent = meta;
    // rest fairness summary
    const counts = {};
    schedule.forEach(r => r.rest.forEach(p => { counts[p.name] = (counts[p.name] || 0) + 1; }));
    const restEntries = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    $("restSummary").innerHTML = restEntries.length
      ? `<div class="rest-line"><b>Rest tally:</b> ${restEntries.map(([n, c]) => `${esc(n)} ×${c}`).join(" · ")}</div>`
      : "";

    // custom notes on the sheet
    $("printNotes").innerHTML = state.customRules.length
      ? `<b>Session notes:</b><ul>${state.customRules.map(r => `<li>${esc(r)}</li>`).join("")}</ul>`
      : "";

    $("output").hidden = false;
    $("tuneCard").hidden = false;
  }

  /* ---------------------------------------------------------------------
     SHARE / PRINT
     --------------------------------------------------------------------- */
  function scheduleToText(schedule, meta) {
    const lines = ["🏸 IFD Badminton Match Scheduler", meta, ""];
    schedule.forEach(rnd => {
      lines.push(`*Round ${rnd.round}*`);
      rnd.matches.forEach((m, i) => {
        const names = (t) => t.map(p => `${p.name}(${p.level})`).join(" & ");
        const mt = matchType(m);
        const tag = mt === "mens" ? "M" : mt === "womens" ? "W" : "X";
        lines.push(`  C${i + 1} [${tag}] ${names(m[0])}  vs  ${names(m[1])}`);
      });
      if (rnd.rest.length) lines.push(`  Rest: ${rnd.rest.map(p => p.name).join(", ")}`);
      lines.push("");
    });
    if (state.customRules.length) {
      lines.push("Notes:");
      state.customRules.forEach(r => lines.push(`- ${r}`));
    }
    return lines.join("\n");
  }

  /* ---------------------------------------------------------------------
     MAIN ACTION
     --------------------------------------------------------------------- */
  function run() {
    $("errMsg").textContent = "";
    const players = readPlayers();
    const named = players.filter(p => p.name);

    if (named.length < 4) { return fail("Add at least 4 named players to build a roaster."); }
    // auto-name any blank rows so counts stay consistent
    players.forEach((p, i) => { if (!p.name) p.name = `Player ${i + 1}`; });

    const courts = clampInt($("numCourts").value, 1, 15, 3);
    const rounds = clampInt($("numRounds").value, 1, 40, 10);
    const maxGap = parseInt($("maxGap").value, 10);

    if (players.length < courts * 4) {
      // not enough players to fill every court — that's allowed, fewer matches run
    }

    const schedule = generateSchedule(players, courts, rounds, maxGap);
    const dur = $("duration").value;
    const meta = `${players.length} players · ${courts} court${courts > 1 ? "s" : ""} · ${rounds} rounds · ~${dur} hr · ${new Date().toLocaleDateString()}`;
    state.lastSchedule = { schedule, meta };
    renderSchedule(schedule, meta);
    $("output").scrollIntoView({ behavior: "smooth", block: "start" });
  }

  function fail(msg) { $("errMsg").textContent = msg; }

  function toast(msg) {
    const t = $("toast");
    t.textContent = msg;
    t.classList.add("show");
    clearTimeout(t._t);
    t._t = setTimeout(() => t.classList.remove("show"), 2200);
  }

  /* ---------------------------------------------------------------------
     CUSTOM RULES UI
     --------------------------------------------------------------------- */
  function renderCustomRules() {
    const ul = $("customRuleList");
    ul.innerHTML = state.customRules.map((r, i) =>
      `<li><span>${esc(r)}</span><button data-i="${i}" title="Remove">✕</button></li>`).join("");
    ul.querySelectorAll("button").forEach(b =>
      b.addEventListener("click", () => {
        state.customRules.splice(+b.dataset.i, 1);
        renderCustomRules();
        if (state.lastSchedule) renderSchedule(state.lastSchedule.schedule, state.lastSchedule.meta);
      }));
  }

  /* ---------------------------------------------------------------------
     WIRE UP
     --------------------------------------------------------------------- */
  function init() {
    buildPlayerRows();

    $("numPlayers").addEventListener("change", buildPlayerRows);
    $("playerList").addEventListener("input", updateBalanceBar);
    $("playerList").addEventListener("change", updateBalanceBar);

    $("duration").addEventListener("input", () => {
      const h = parseFloat($("duration").value) || 0;
      const r = Math.max(1, Math.round(h * 5));
      $("numRounds").value = r;             // rule A: ~5 rounds/hr
    });

    $("fillSample").addEventListener("click", () => {
      const rows = [...document.querySelectorAll(".player-row")];
      rows.forEach((r, i) => {
        r.querySelector(".p-name").value = SAMPLE[i % SAMPLE.length] + (i >= SAMPLE.length ? " " + (i + 1) : "");
        r.querySelector(".p-level").value = LEVELS[i % 4];
        r.querySelector(".p-woman").checked = i % 3 === 1; // ~33% women
      });
      updateBalanceBar();
    });

    $("clearNames").addEventListener("click", () => {
      document.querySelectorAll(".p-name").forEach(i => i.value = "");
      updateBalanceBar();
    });

    $("generate").addEventListener("click", run);
    $("rebuild").addEventListener("click", run);

    $("addRule").addEventListener("click", () => {
      const v = $("customRuleInput").value.trim();
      if (!v) return;
      state.customRules.push(v);
      $("customRuleInput").value = "";
      renderCustomRules();
      if (state.lastSchedule) renderSchedule(state.lastSchedule.schedule, state.lastSchedule.meta);
    });
    $("customRuleInput").addEventListener("keydown", e => { if (e.key === "Enter") $("addRule").click(); });

    $("printBtn").addEventListener("click", () => window.print());

    $("shareWa").addEventListener("click", () => {
      if (!state.lastSchedule) return;
      const txt = scheduleToText(state.lastSchedule.schedule, state.lastSchedule.meta);
      window.open("https://wa.me/?text=" + encodeURIComponent(txt), "_blank");
    });

    $("copyText").addEventListener("click", async () => {
      if (!state.lastSchedule) return;
      const txt = scheduleToText(state.lastSchedule.schedule, state.lastSchedule.meta);
      try { await navigator.clipboard.writeText(txt); toast("Schedule copied ✓"); }
      catch { toast("Copy failed — long-press to select"); }
    });
  }

  document.addEventListener("DOMContentLoaded", init);
})();

