      const block = document.createElement("div");
      block.className = "round-block";
      const rows = rnd.matches.map((m, i) => {
        const mt = matchType(m);
        return `<tr>
          <td class="court-col">${i + 1}</td>
          <td class="team">${teamHtml(m[0])}</td>
          <td class="vs">vs</td>
