        ? `<div class="rest-line">🪑 <b>Resting:</b> ${rnd.rest.map(p => esc(p.name)).join(", ")}</div>` : "";
      const relaxNote = rnd.relaxed >= 2
        ? ' <span class="tag" title="Level gap relaxed to fill the schedule (rule I)">↯ levels relaxed</span>'
