      updateBalanceBar();
    });

    $("generate").addEventListener("click", run);
    $("rebuild").addEventListener("click", run);

    $("addRule").addEventListener("click", () => {
      const v = $("customRuleInput").value.trim();
      if (!v) return;
      state.customRules.push(v);
      $("customRuleInput").value = "";
